// // Concatenates an 8-bit input (In0) with a 2-bit input (In1) to produce a 10-bit output (dout). The most significant 8 bits of dout are derived from In0, while the least significant 2 bits come from In1.
module top_module(In0,In1,dout);input [7:0]In0; 
  input [1:0]In1; 
  output [9:0]dout; 
  wire [7:0]In0; 
  wire [1:0]In1; 
  assign dout[9:8] = In1; 
  assign dout[7:0] = In0; 
 endmodule
